/*
The personnel directory (D-PersonGlobal). Reads gate on `person.read` via the read-scope rule
(D-PersonReadScope); writes on `person.create`/`person.update`/`person.rank.assign`/
`person.lifecycle`/`person.purge` — all enforced once authorization (M7) lands. Writes are
audited in-process (D-Audit). The module never reads rank to make a decision (D-Rank).
*/
type PersonServiceClientWithAuth interface {
	// Create a person (no account, no unit needed). Returns Person:PersonConflict if the code is taken.
	CreatePerson(ctx context.Context, requestArg CreatePersonRequest) (Person, error)
	// Read one person with its name variants, citizenships, and residences.
	GetPerson(ctx context.Context, personIdArg string) (Person, error)
	// Update names, birthdate, sex, country_of_birth, attributes. `code` is immutable; rank via setRank.
	UpdatePerson(ctx context.Context, personIdArg string, requestArg UpdatePersonRequest) (Person, error)
	// Search/list the directory, token-paginated. (The read-scope union is applied once authz lands, M7.)
	ListPersons(ctx context.Context, pageSizeArg *int, pageTokenArg *string) (PersonPage, error)
	// Set or clear the person's one rank (a directory attribute; D-Rank). Returns Person:PersonInvalid for an unknown rank.
	SetRank(ctx context.Context, personIdArg string, requestArg SetRankRequest) (Person, error)
	// Begin reversible deactivation (opens the grace window before purge).
	DeactivatePerson(ctx context.Context, personIdArg string, requestArg DeactivateRequest) (Person, error)
	// Cancel deactivation within the grace window. Returns Person:PersonLifecycleConflict if not deactivated.
	ReactivatePerson(ctx context.Context, personIdArg string) (Person, error)
	/*
	   Hard-erase PII after the grace window (idempotent): NULLs every PII column and removes
	   citizenship/residence/name-variant rows, keeping the id as a tombstone so audit history
	   stays intact. Returns Person:PersonLifecycleConflict before purgeAfter.
	*/
	PurgePerson(ctx context.Context, personIdArg string) (Person, error)
	// Add or replace a locale name form (transliteration). Keyed by (person, locale).
	UpsertNameVariant(ctx context.Context, personIdArg string, requestArg UpsertNameVariantRequest) (NameVariant, error)
	// Remove a name variant.
	DeleteNameVariant(ctx context.Context, personIdArg string, localeArg string) error
	// List a person's citizenships.
	ListCitizenships(ctx context.Context, personIdArg string) ([]Citizenship, error)
	// Add or replace the active citizenship for a country. Returns Person:PersonInvalid for an unknown country.
	UpsertCitizenship(ctx context.Context, personIdArg string, requestArg UpsertCitizenshipRequest) (Citizenship, error)
	// Remove a citizenship by country code.
	DeleteCitizenship(ctx context.Context, personIdArg string, countryArg string) error
	// List a person's residence history.
	ListResidences(ctx context.Context, personIdArg string) ([]Residence, error)
	// Add a residence row, or replace one when id is supplied. Returns Person:PersonInvalid for an unknown country.
	UpsertResidence(ctx context.Context, personIdArg string, requestArg UpsertResidenceRequest) (Residence, error)
	// Remove a residence row by id.
	DeleteResidence(ctx context.Context, personIdArg string, residenceIdArg string) error
	// List a person's contact emails.
	ListEmails(ctx context.Context, personIdArg string) ([]Email, error)
	// Add or replace a contact email. Returns Person:PersonConflict if the address is taken, Person:PersonInvalid for an unknown type or malformed address.
	UpsertEmail(ctx context.Context, personIdArg string, requestArg UpsertEmailRequest) (Email, error)
	// Remove a contact email by id.
	DeleteEmail(ctx context.Context, personIdArg string, emailIdArg string) error
	// List a person's contact phones.
	ListPhones(ctx context.Context, personIdArg string) ([]Phone, error)
	// Add or replace a contact phone. Returns Person:PersonConflict if the number is taken, Person:PersonInvalid for an unknown type or unparseable number.
	UpsertPhone(ctx context.Context, personIdArg string, requestArg UpsertPhoneRequest) (Phone, error)
	// Remove a contact phone by id.
	DeletePhone(ctx context.Context, personIdArg string, phoneIdArg string) error
	// List a person's call signs.
	ListCallSigns(ctx context.Context, personIdArg string) ([]CallSign, error)
	// Add or replace a call sign. Returns Person:PersonConflict if the value is already held by the person.
	UpsertCallSign(ctx context.Context, personIdArg string, requestArg UpsertCallSignRequest) (CallSign, error)
	// Remove a call sign by id.
	DeleteCallSign(ctx context.Context, personIdArg string, callSignIdArg string) error
	// List the contact-email type catalog (locale -> text names; D-i18n).
	ListEmailTypes(ctx context.Context) ([]EmailType, error)
	// List the contact-phone type catalog (locale -> text names; D-i18n).
	ListPhoneTypes(ctx context.Context) ([]PhoneType, error)
}

